create extension if not exists vector;
create table profiles (id uuid primary key references auth.users(id) on delete cascade, full_name text, phone text, created_at timestamptz default now());
create table salons (id uuid primary key default gen_random_uuid(), owner_id uuid references profiles(id) on delete cascade, name text not null default 'My Salon', niche text not null, employee_name text not null default 'Amina', communication_style text not null default 'Premium Concierge', training_status text not null default 'not_started', tone_profile jsonb not null default '{}', created_at timestamptz default now());
create table integrations (id uuid primary key default gen_random_uuid(), salon_id uuid references salons(id) on delete cascade, provider text not null, status text not null default 'disconnected', credentials jsonb not null default '{}', webhook_url text, created_at timestamptz default now(), unique(salon_id, provider));
create table training_documents (id uuid primary key default gen_random_uuid(), salon_id uuid references salons(id) on delete cascade, file_name text not null, source_type text not null, extracted_text text not null, insights jsonb not null default '{}', created_at timestamptz default now());
create table knowledge_chunks (id uuid primary key default gen_random_uuid(), salon_id uuid references salons(id) on delete cascade, document_id uuid references training_documents(id) on delete cascade, source_type text not null, content text not null, embedding vector(1536), created_at timestamptz default now());
create index knowledge_chunks_embedding_idx on knowledge_chunks using ivfflat (embedding vector_cosine_ops) with (lists = 100);
create table customers (id uuid primary key default gen_random_uuid(), salon_id uuid references salons(id) on delete cascade, telegram_chat_id text, name text, phone text, tags text[] default '{}', status text not null default 'New Lead', created_at timestamptz default now(), unique(salon_id, telegram_chat_id));
create table conversations (id uuid primary key default gen_random_uuid(), salon_id uuid references salons(id) on delete cascade, customer_id uuid references customers(id) on delete cascade, channel text not null, external_id text not null, status text not null default 'open', ai_paused boolean not null default false, created_at timestamptz default now(), unique(salon_id, channel, external_id));
create table messages (id uuid primary key default gen_random_uuid(), conversation_id uuid references conversations(id) on delete cascade, sender text not null check (sender in ('customer','ai','human','system')), body text not null, metadata jsonb not null default '{}', created_at timestamptz default now());
create table appointments (id uuid primary key default gen_random_uuid(), salon_id uuid references salons(id) on delete cascade, customer_id uuid references customers(id) on delete cascade, service text not null, starts_at timestamptz not null, status text not null default 'booked', price_kzt integer, notes text, created_at timestamptz default now());
create table customer_memories (id uuid primary key default gen_random_uuid(), salon_id uuid references salons(id) on delete cascade, customer_id uuid references customers(id) on delete cascade, memory text not null, confidence numeric default .8, created_at timestamptz default now());
create or replace function match_knowledge_chunks(query_embedding vector(1536), match_count int, filter_salon_id uuid) returns table(id uuid, content text, source_type text, similarity float) language sql stable as $$ select knowledge_chunks.id, knowledge_chunks.content, knowledge_chunks.source_type, 1 - (knowledge_chunks.embedding <=> query_embedding) as similarity from knowledge_chunks where salon_id = filter_salon_id order by knowledge_chunks.embedding <=> query_embedding limit match_count; $$;
alter table profiles enable row level security; alter table salons enable row level security; alter table integrations enable row level security; alter table training_documents enable row level security; alter table knowledge_chunks enable row level security; alter table customers enable row level security; alter table conversations enable row level security; alter table messages enable row level security; alter table appointments enable row level security; alter table customer_memories enable row level security;
create policy "profiles own rows" on profiles for all using (auth.uid() = id) with check (auth.uid() = id);
create policy "salon owners" on salons for all using (owner_id = auth.uid()) with check (owner_id = auth.uid());
create policy "owner integrations" on integrations for all using (exists (select 1 from salons where salons.id = salon_id and salons.owner_id = auth.uid())) with check (exists (select 1 from salons where salons.id = salon_id and salons.owner_id = auth.uid()));
create policy "owner training docs" on training_documents for all using (exists (select 1 from salons where salons.id = salon_id and salons.owner_id = auth.uid())) with check (exists (select 1 from salons where salons.id = salon_id and salons.owner_id = auth.uid()));
create policy "owner chunks" on knowledge_chunks for all using (exists (select 1 from salons where salons.id = salon_id and salons.owner_id = auth.uid())) with check (exists (select 1 from salons where salons.id = salon_id and salons.owner_id = auth.uid()));
create policy "owner customers" on customers for all using (exists (select 1 from salons where salons.id = salon_id and salons.owner_id = auth.uid())) with check (exists (select 1 from salons where salons.id = salon_id and salons.owner_id = auth.uid()));
create policy "owner conversations" on conversations for all using (exists (select 1 from salons where salons.id = salon_id and salons.owner_id = auth.uid())) with check (exists (select 1 from salons where salons.id = salon_id and salons.owner_id = auth.uid()));
create policy "owner messages" on messages for all using (exists (select 1 from conversations c join salons s on s.id = c.salon_id where c.id = conversation_id and s.owner_id = auth.uid())) with check (exists (select 1 from conversations c join salons s on s.id = c.salon_id where c.id = conversation_id and s.owner_id = auth.uid()));
create policy "owner appointments" on appointments for all using (exists (select 1 from salons where salons.id = salon_id and salons.owner_id = auth.uid())) with check (exists (select 1 from salons where salons.id = salon_id and salons.owner_id = auth.uid()));
create policy "owner memories" on customer_memories for all using (exists (select 1 from salons where salons.id = salon_id and salons.owner_id = auth.uid())) with check (exists (select 1 from salons where salons.id = salon_id and salons.owner_id = auth.uid()));
